--
-- TOC entry 516 (class 1259 OID 17308)
-- Name: axiinttracker_summ_view; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.axiinttracker_summ_view AS
 SELECT row_number() OVER (ORDER BY axiinttracker.script) AS axiinttracker_summ_tid,
    (row_number() OVER (ORDER BY axiinttracker.script))::character varying AS rowstamp,
    ( SELECT axiintobjdetail.objectname
           FROM axioma.axiintobjdetail
          WHERE ((axiintobjdetail.parentobjid IS NULL) AND ((axiintobjdetail.intobjectname)::text = regexp_replace((axiinttracker.script)::text, 'OSIN.'::text, ''::text, 'g'::text)))) AS objectname,
    axiinttracker.script,
    count(*) AS attempts,
    sum(axiinttracker.success) AS successes
   FROM axioma.axiinttracker
  GROUP BY axiinttracker.script;


ALTER VIEW axioma.axiinttracker_summ_view OWNER TO axioma;

