--
-- TOC entry 821 (class 1259 OID 18055)
-- Name: orgfilter; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.orgfilter AS
 SELECT siteauth.orgid,
    groupuser.userid,
    applicationauth.app
   FROM axioma.siteauth,
    axioma.groupuser,
    axioma.axigroup,
    axioma.applicationauth
  WHERE (((groupuser.groupname)::text = (siteauth.groupname)::text) AND ((groupuser.groupname)::text = (axigroup.groupname)::text) AND (axigroup.independent = 1) AND ((siteauth.groupname)::text = (applicationauth.groupname)::text))
UNION ALL
 SELECT a.orgid,
    b.userid,
    c1.app
   FROM axioma.siteauth a,
    axioma.groupuser b,
    (axioma.axigroup m
     LEFT JOIN axioma.applicationauth c1 ON (((c1.groupname)::text IN ( SELECT applicationauth.groupname
           FROM axioma.applicationauth
          WHERE ((applicationauth.app)::text = (c1.app)::text)))))
  WHERE (((b.groupname)::text = (a.groupname)::text) AND ((b.groupname)::text = (m.groupname)::text) AND (m.independent = 0) AND (EXISTS ( SELECT 1
           FROM axioma.axigroup m2,
            axioma.applicationauth c,
            axioma.groupuser d
          WHERE (((d.userid)::text = (b.userid)::text) AND ((d.groupname)::text = (m2.groupname)::text) AND ((d.groupname)::text = (c.groupname)::text) AND (m2.independent = 0) AND (((c.app)::text = (c1.app)::text) OR (c1.app IS NULL))))));


ALTER VIEW axioma.orgfilter OWNER TO axioma;

