--
-- TOC entry 824 (class 1259 OID 18068)
-- Name: companysetfilter; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.companysetfilter AS
 SELECT DISTINCT sets.setid,
    groupuser.userid,
    applicationauth.app
   FROM axioma.sets,
    axioma.organization,
    axioma.groupuser,
    axioma.applicationauth
  WHERE (((sets.setid)::text = (organization.companysetid)::text) AND ((sets.settype)::text IN ( SELECT synonymdomain.value
           FROM axioma.synonymdomain
          WHERE (((synonymdomain.domainid)::text = 'SETTYPE'::text) AND ((synonymdomain.maxvalue)::text = 'COMPANY'::text)))) AND ((organization.orgid)::text IN ( SELECT orgfilter.orgid
           FROM axioma.orgfilter
          WHERE (((orgfilter.userid)::text = (groupuser.userid)::text) AND ((orgfilter.app)::text = (applicationauth.app)::text)))));


