CREATE VIEW axioma.computersystem AS
 SELECT deployedasset.assetclass,
    deployedasset.assettag,
    dpacomputer.biosdate,
    dpacomputer.biosname,
    dpacomputer.biospnp,
    dpacomputer.biosversion,
    dpacomputer.changedate,
    deployedasset.changedate AS changedate1,
    dpacomputer.createdate,
    deployedasset.createdate AS createdate1,
    deployedasset.description,
    deployedasset.domainname,
    deployedasset.guid,
    deployedasset.hwdetectiontool,
    deployedasset.hwlastscandate,
    dpacomputer.logonname,
    deployedasset.makemodel,
    deployedasset.manufacturer,
    dpacomputer.moboassettag,
    dpacomputer.mobochipset,
    dpacomputer.mobodescription,
    dpacomputer.mobomakemodel,
    dpacomputer.mobomanufacturer,
    dpacomputer.moboserialnumber,
    dpacomputer.nodeid,
    deployedasset.nodeid AS nodeid1,
    deployedasset.nodename,
    deployedasset.orgid,
    dpacomputer.ramdescription,
    dpacomputer.ramsize,
    dpacomputer.ramtotalslots,
    dpacomputer.ramtype,
    dpacomputer.ramunit,
    dpacomputer.ramunusedslots,
    dpacomputer.rowstamp,
    deployedasset.rowstamp AS rowstamp1,
    deployedasset.serialnumber,
    deployedasset.siteid,
    dpacomputer.smbios,
    deployedasset.sourceid,
    deployedasset.supportssnmp,
    dpacomputer.supportswmi,
    dpacomputer.swdetectiontool,
    dpacomputer.swlastscandate,
    deployedasset.systemrole,
    dpammanuvariant.manufacturername AS cmanufacturer,
    dpammanuvariant.manufacturervar,
    dpammanuvariant.dpammanuvariantid,
    dpammanuvariant.rowstamp AS rowstamp2,
    dpacomputer.plantcode1,
    dpacomputer.msus1,
    dpacomputer.mips1,
    dpacomputer.capacitymodel1,
    dpacomputer.numcpuconfig1,
    dpacomputer.numcputotal1,
    deployedasset.tloamnrsguid,
    deployedasset.tloamnrssignature,
    deployedasset.tloamnrsvmid,
    deployedasset.tloamnrsmanufacturer,
    deployedasset.tloamnrsmodel,
    deployedasset.tloamnrsserialnumber,
    deployedasset.tloamnrssystemboarduuid,
    deployedasset.tloamnrsprimarymacaddress,
    deployedasset.tloamnrshostsystem,
    deployedasset.tloamnrsname,
    deployedasset.tloamispromoted,
    deployedasset.tloamnrsmanagedsystemname,
    deployedasset.tloamhwtype,
    deployedasset.tloamstatus,
    dpacomputer.tloamparentid,
    deployedasset.tloamhash,
    dpacomputer.tloamplatformbase,
    dpacomputer.numcoretotal,
    deployedasset.tloamnrsuuid
   FROM axioma.deployedasset,
    axioma.dpacomputer,
    axioma.dpammanuvariant
  WHERE ((dpacomputer.nodeid = deployedasset.nodeid) AND ((deployedasset.manufacturer)::text = (dpammanuvariant.manufacturervar)::text));


ALTER VIEW axioma.computersystem OWNER TO axioma;

