 SELECT dpasoftware.nodeid,
    dpasoftware.softwareid,
    dpasoftware.suiteid,
    dpasoftware.softwarename,
    dpasoftware.language,
    dpasoftware.version,
    dpasoftware.licensedorg,
    dpasoftware.licenseduser,
    dpasoftware.usagecount,
    dpasoftware.lastusagedate,
    dpasoftware.installpath,
    dpasoftware.installdate,
    dpasoftware.serialnumber,
    dpasoftware.productid,
    dpasoftware.manufacturer,
    dpasoftware.description,
    dpasoftware.createdate,
    dpasoftware.changedate,
    dpasoftware.type,
    dpasoftware.firstencountered1,
    dpasoftware.lastencountered1,
    dpasoftware.tloamsoftwareid,
    dpasoftware.rowstamp,
    t800.swname AS softwarevariant,
    t800.tloamsoftwareid AS dpamswvariantid,
    t800.rowstamp AS rowstamp1,
    dpammanuvariant.manufacturername AS cmanufacturer,
    dpammanuvariant.manufacturervar,
    dpammanuvariant.dpammanuvariantid,
    dpammanuvariant.rowstamp AS rowstamp2,
    tloamsoftware.swname AS csoftwarename,
    tloamsoftware.swname AS swname1,
    tloamsoftware.tloamsoftwareid AS softwareid1,
    tloamsoftware.managedas AS compliancesetting,
    tloamsoftware.rowstamp AS rowstamp3,
    tloamsoftware.swname AS tloamswname,
    tloamsoftware.version AS tloamversion,
    tloamsoftware.release AS tloamrelease,
    tloamsoftware.type AS tloamtype,
    tloamsoftware.platformbase AS tloamplatformbase,
    tloamsoftware.func AS tloamfunc
   FROM axioma.dpasoftware,
    axioma.tloamsoftware t800,
    axioma.tloamsoftware,
    axioma.dpammanuvariant
  WHERE ((t800.tloamsoftwareid = dpasoftware.tloamsoftwareid) AND (tloamsoftware.tloamsoftwareid =
        CASE
            WHEN ((t800.targetsoftwareid IS NULL) OR (t800.targetsoftwareid = 0)) THEN t800.tloamsoftwareid
            ELSE (t800.targetsoftwareid)::bigint
        END) AND ((dpammanuvariant.manufacturervar)::text = (tloamsoftware.manufacturer)::text));


