--
-- TOC entry 1152 (class 1259 OID 18924)
-- Name: fs_index1; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.fs_index1 AS
 SELECT n.nspname AS namespace,
    t.relname AS tablename,
    i.relname AS indexname,
    axioma.icount((ix.indkey)::integer[]) AS colcount,
    a.attname AS colname,
    axioma.idx((ix.indkey)::integer[], (a.attnum)::integer) AS colseq,
    ix.indisprimary AS isprimary,
    ix.indisunique AS isunique,
    ix.indisclustered AS isclustered,
    (((ix.indoption[(axioma.idx((ix.indkey)::integer[], (a.attnum)::integer) - 1)])::integer & 1) = 1) AS coldesc,
    a.attnum AS indexcolkey,
    ix.indkey AS indexkeys,
    ix.indoption AS indexoptions
   FROM ((((pg_class t
     JOIN pg_index ix ON ((t.oid = ix.indrelid)))
     JOIN pg_class i ON ((i.oid = ix.indexrelid)))
     LEFT JOIN pg_namespace n ON ((i.relnamespace = n.oid)))
     JOIN pg_attribute a ON ((a.attrelid = t.oid)))
  WHERE ((a.attnum = ANY ((ix.indkey)::smallint[])) AND (t.relkind = 'r'::"char"));


ALTER VIEW axioma.fs_index1 OWNER TO axioma;

