-- TOC entry 1291 (class 1259 OID 19286)
-- Name: itemsetfilter; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.itemsetfilter AS
 SELECT DISTINCT sets.setid,
    groupuser.userid,
    applicationauth.app
   FROM axioma.sets,
    axioma.organization,
    axioma.groupuser,
    axioma.applicationauth
  WHERE (((sets.setid)::text = (organization.itemsetid)::text) AND ((sets.settype)::text IN ( SELECT synonymdomain.value
           FROM axioma.synonymdomain
          WHERE (((synonymdomain.domainid)::text = 'SETTYPE'::text) AND ((synonymdomain.maxvalue)::text = 'ITEM'::text)))) AND ((organization.orgid)::text IN ( SELECT orgfilter.orgid
           FROM axioma.orgfilter
          WHERE (((orgfilter.userid)::text = (groupuser.userid)::text) AND ((orgfilter.app)::text = (applicationauth.app)::text)))));


ALTER VIEW axioma.itemsetfilter OWNER TO axioma;

