--
-- TOC entry 2526 (class 1259 OID 50654)
-- Name: laboravailview; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.laboravailview AS
 SELECT (((final.workperiodid)::text || (final.laborcraftrateid)::text))::integer AS laborviewtid,
    final.laborcode,
    final.orgid,
    final.craft,
    final.skilllevel,
    final.workdate,
    final.workperiod_start AS wpstart,
    final.workperiod_end AS wpend,
    final.available_no_assign AS moddedavailhrs,
    final.totalworkhrs,
    final.assignedhrs,
    ((final.available_no_assign)::double precision - final.assignedhrs) AS availableworkhrs,
    final.rowstamp
   FROM ( SELECT laborwithperiods.laborcode,
            laborwithperiods.workdate,
            laborwithperiods.orgid,
            laborwithperiods.craft,
            laborwithperiods.skilllevel,
            max(laborwithperiods.workperiodid) AS workperiodid,
            max(laborwithperiods.workperiod_start) AS workperiod_start,
            max(laborwithperiods.workperiod_end) AS workperiod_end,
            max(laborwithperiods.laborcraftrateid) AS laborcraftrateid,
            max((laborwithperiods.rowstamp)::text) AS rowstamp,
            (EXTRACT(epoch FROM (laborwithperiods.workperiod_end - laborwithperiods.workperiod_start)) / (60)::numeric) AS totalworkhrs,
            GREATEST((sum((EXTRACT(epoch FROM (laborwithperiods.workperiod_end - laborwithperiods.workperiod_start)) / (60)::numeric)) + sum(
                CASE
                    WHEN (((laborwithperiods.mod_start < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_start > laborwithperiods.workperiod_end)) AND ((laborwithperiods.mod_end < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_end > laborwithperiods.workperiod_end)) AND ((laborwithperiods.type)::text = 'NON-WORK'::text)) THEN (0)::numeric
                    WHEN (((laborwithperiods.mod_start < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_start > laborwithperiods.workperiod_end)) AND ((laborwithperiods.mod_end < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_end > laborwithperiods.workperiod_end)) AND ((laborwithperiods.type)::text = 'WORK'::text)) THEN (EXTRACT(epoch FROM (laborwithperiods.mod_end - laborwithperiods.mod_start)) / (60)::numeric)
                    WHEN ((laborwithperiods.mod_start >= laborwithperiods.workperiod_start) AND (laborwithperiods.mod_start <= laborwithperiods.workperiod_end) AND ((laborwithperiods.mod_end < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_end > laborwithperiods.workperiod_end)) AND ((laborwithperiods.type)::text = 'NON-WORK'::text)) THEN ((- EXTRACT(epoch FROM (laborwithperiods.workperiod_end - laborwithperiods.mod_start))) / (60)::numeric)
                    WHEN ((laborwithperiods.mod_start >= laborwithperiods.workperiod_start) AND (laborwithperiods.mod_start <= laborwithperiods.workperiod_end) AND ((laborwithperiods.mod_end < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_end > laborwithperiods.workperiod_end)) AND ((laborwithperiods.type)::text = 'WORK'::text)) THEN (EXTRACT(epoch FROM (laborwithperiods.mod_end - laborwithperiods.workperiod_end)) / (60)::numeric)
                    WHEN ((laborwithperiods.mod_end >= laborwithperiods.workperiod_start) AND (laborwithperiods.mod_end <= laborwithperiods.workperiod_end) AND ((laborwithperiods.mod_start < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_start > laborwithperiods.workperiod_end)) AND ((laborwithperiods.type)::text = 'NON-WORK'::text)) THEN ((- EXTRACT(epoch FROM (laborwithperiods.mod_end - laborwithperiods.workperiod_start))) / (60)::numeric)
                    WHEN ((laborwithperiods.mod_end >= laborwithperiods.workperiod_start) AND (laborwithperiods.mod_end <= laborwithperiods.workperiod_end) AND ((laborwithperiods.mod_start < laborwithperiods.workperiod_start) OR (laborwithperiods.mod_start > laborwithperiods.workperiod_end)) AND ((laborwithperiods.type)::text = 'WORK'::text)) THEN (EXTRACT(epoch FROM (laborwithperiods.workperiod_start - laborwithperiods.mod_start)) / (60)::numeric)
                    ELSE (0)::numeric
                END)), (0)::numeric) AS available_no_assign,
            sum(COALESCE((assigns.laborhrs * (60)::double precision), (0)::double precision)) AS assignedhrs
           FROM (( SELECT laborcraftrate.laborcode,
                    laborcraftrate.orgid,
                    laborcraftrate.craft,
                    laborcraftrate.skilllevel,
                    laborcraftrate.laborcraftrateid,
                    workperiod.workdate,
                    workperiod.workperiodid,
                    workperiod.rowstamp,
                    (((workperiod.workdate || ' '::text) || workperiod.starttime))::timestamp without time zone AS workperiod_start,
                    (
                        CASE
                            WHEN (((workperiod.workdate || ' '::text) || workperiod.endtime) <= ((workperiod.workdate || ' '::text) || workperiod.starttime)) THEN (("left"((((workperiod.workdate + '1 day'::interval))::character varying)::text, 10) || ' '::text) || workperiod.endtime)
                            ELSE ((workperiod.workdate || ' '::text) || workperiod.endtime)
                        END)::timestamp without time zone AS workperiod_end,
                    (((modavail.workdate || ' '::text) || modavail.starttime))::timestamp without time zone AS mod_start,
                    (
                        CASE
                            WHEN (((modavail.workdate || ' '::text) || modavail.endtime) <= ((modavail.workdate || ' '::text) || modavail.starttime)) THEN (("left"((((modavail.workdate + '1 day'::interval))::character varying)::text, 10) || ' '::text) || modavail.endtime)
                            ELSE ((modavail.workdate || ' '::text) || modavail.endtime)
                        END)::timestamp without time zone AS mod_end,
                    modavailreason.maxvalue AS type
                   FROM (((((axioma.person
                     LEFT JOIN axioma.personcal ON (((person.personid)::text = (personcal.personid)::text)))
                     LEFT JOIN axioma.laborcraftrate ON ((((laborcraftrate.laborcode)::text = (( SELECT labor.laborcode
                           FROM axioma.labor
                          WHERE ((labor.personid)::text = (person.personid)::text)))::text) AND (laborcraftrate.defaultcraft = 1))))
                     LEFT JOIN axioma.workperiod ON (((workperiod.calnum)::text = (personcal.calnum)::text)))
                     LEFT JOIN axioma.modavail ON ((((modavail.personid)::text = (person.personid)::text) AND (modavail.workdate = workperiod.workdate))))
                     LEFT JOIN axioma.synonymdomain modavailreason ON ((((modavail.reasoncode)::text = (modavailreason.value)::text) AND ((modavailreason.domainid)::text = 'RSNCODE'::text))))
                  WHERE ((personcal.calnum IS NOT NULL) AND (laborcraftrate.laborcode IS NOT NULL))) laborwithperiods
             LEFT JOIN ( SELECT assignment.laborcode,
                    sum(assignment.laborhrs) AS laborhrs,
                    (assignment.scheduledate)::date AS ondate
                   FROM axioma.assignment
                  GROUP BY assignment.laborcode, ((assignment.scheduledate)::date)) assigns ON ((((assigns.laborcode)::text = (laborwithperiods.laborcode)::text) AND (assigns.ondate = laborwithperiods.workdate))))
          GROUP BY laborwithperiods.laborcode, laborwithperiods.orgid, laborwithperiods.craft, laborwithperiods.skilllevel, laborwithperiods.workperiod_start, laborwithperiods.workperiod_end, laborwithperiods.workdate
          ORDER BY laborwithperiods.laborcode, (max(laborwithperiods.workperiod_start))) final;


