-- TOC entry 2522 (class 1259 OID 50607)
-- Name: lbscrewview; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.lbscrewview AS
 SELECT lbs.refobject,
    lbs.key1,
    lbs.key2,
    lbs.longitude,
    lbs.latitude,
    lbs.altitude,
    lbs.locationaccuracy,
    lbs.altitudeaccuracy,
    lbs.heading,
    lbs.speed,
    lbs.lastupdate,
    cr.amcrewid,
    cr.amcrew,
    cr.orgid,
    cr.shiftnum
   FROM (axioma.lbslocation lbs
     LEFT JOIN axioma.amcrew cr ON ((((lbs.key1)::text = (cr.orgid)::text) AND ((lbs.key2)::text = (cr.amcrew)::text))))
  WHERE (((lbs.refobject)::text = 'AMCREW'::text) AND ((cr.status)::text IN ( SELECT synonymdomain.value
           FROM axioma.synonymdomain
          WHERE (((synonymdomain.domainid)::text = 'CREWSTATUS'::text) AND ((synonymdomain.maxvalue)::text = 'ACTIVE'::text)))));


