--

CREATE VIEW axioma.lbslaborview AS
 SELECT lbs.refobject,
    lbs.key1,
    lbs.key2,
    lbs.longitude,
    lbs.latitude,
    lbs.altitude,
    lbs.locationaccuracy,
    lbs.altitudeaccuracy,
    lbs.heading,
    lbs.speed,
    lbs.lastupdate,
    lb.laborid,
    lb.laborcode,
    lb.orgid,
    am.amcrew,
    am.effectivedate,
    am.enddate,
    p.shiftnum
   FROM (((axioma.lbslocation lbs
     LEFT JOIN axioma.labor lb ON ((((lbs.key1)::text = (lb.orgid)::text) AND ((lbs.key2)::text = (lb.laborcode)::text))))
     LEFT JOIN axioma.amcrewlabor am ON ((((lb.laborcode)::text = (am.laborcode)::text) AND ((lb.orgid)::text = (am.orgid)::text))))
     LEFT JOIN axioma.personcal p ON ((((lb.laborcode)::text = (p.personid)::text) AND ((lb.orgid)::text = (p.orgid)::text))))
  WHERE (((lbs.refobject)::text = 'LABOR'::text) AND ((lb.status)::text IN ( SELECT synonymdomain.value
           FROM axioma.synonymdomain
          WHERE (((synonymdomain.domainid)::text = 'LABORSTATUS'::text) AND ((synonymdomain.maxvalue)::text = 'ACTIVE'::text)))));


