--
-- TOC entry 1595 (class 1259 OID 20060)
-- Name: masterview; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.masterview AS
 SELECT contractmaster.acceptanceloss,
    contractmaster.acceptperiod,
    contract.autoextendperiod,
    contract.buyahead,
    contractmaster.canexceedvolume,
    contract.changeby,
    contract.changedate,
    contract.condforext,
    contract.contact,
    contract.contactperson,
    contract.contractid,
    contractmaster.contractmasterid,
    contract.contractnum,
    contractmaster.contractnum AS contractnum1,
    contract.contracttype,
    contract.currencycode,
    contract.custnotifyperiod,
    contract.customernum,
    contract.custtermallowed,
    contract.description,
    contract.enddate,
    contract.exchangedate,
    contract.exchangerate,
    contract.exchangerate2,
    contract.extendable,
    contract.externalrefid,
    contract.fob,
    contract.freightterms,
    contract.hasinsurance,
    contract.hasld,
    contract.historyflag,
    contract.inclusive1,
    contract.inclusive2,
    contract.inclusive3,
    contract.inclusive4,
    contract.inclusive5,
    contract.inspectionrequired,
    contract.insuranceexpdate,
    contract.langcode,
    contractmaster.lastassocdate,
    contract.masternum,
    contract.masterrevnum,
    contractmaster.maxvol,
    contract.orgid,
    contractmaster.orgid AS orgid1,
    contract.ownersysid,
    contract.paymentsched,
    contract.paymentterms,
    contract.porequired,
    contract.processclaim,
    contract.purchaseagent,
    contract.reatcntrctsubject,
    contract.reatcontcurator,
    contract.renewaldate,
    contract.revcomments,
    contract.revisionnum,
    contractmaster.revisionnum AS revisionnum1,
    contract.rowstamp,
    contractmaster.rowstamp AS rowstamp1,
    contract.sendersysid,
    contractmaster.shippingloss,
    contract.shipvia,
    contract.startdate,
    contract.status,
    contract.statusdate,
    contract.test,
    contract.totalbasecost,
    contract.totalcost,
    contract.vendnotifyperiod,
    contract.vendor,
    contract.vendorrefnum,
    contract.vendtermallowed
   FROM axioma.contractmaster,
    axioma.contract
  WHERE (((contract.contractnum)::text = (contractmaster.contractnum)::text) AND (contract.revisionnum = contractmaster.revisionnum) AND ((contract.orgid)::text = (contractmaster.orgid)::text) AND ((contract.contracttype)::text IN ( SELECT synonymdomain.value
           FROM axioma.synonymdomain
          WHERE (((synonymdomain.domainid)::text = 'CONTRACTTYPE'::text) AND ((synonymdomain.maxvalue)::text = 'MASTER'::text)))));


ALTER VIEW axioma.masterview OWNER TO axioma;

