    person.delegate,
    person.delegatefromdate,
    person.delegatetodate,
    person.pcardnum,
    person.pcardtype,
    person.pcardexpdate,
    person.pcardverification,
    person.addressline1,
    person.addressline2,
    person.addressline3,
    person.city,
    person.regiondistrict,
    person.county,
    person.stateprovince,
    person.country,
    person.postalcode,
    person.vip,
    person.statusdate,
    person.acceptingwfmail,
    person.wopriority,
    person.loctoservreq,
    person.personuid,
    person.langcode,
    person.sendersysid,
    person.sourcesysid,
    person.ownersysid,
    person.externalrefid,
    person.language,
    person.locale,
    person.timezone,
    person.hasld,
    person.rowstamp,
    persongroupteam.resppartygroup,
    persongroupteam.respparty,
    persongroupteam.resppartygroupseq,
    persongroupteam.resppartyseq,
    persongroupteam.usefororg,
    persongroupteam.useforsite,
    persongroupteam.groupdefault,
