    skdworkplanextcap.rank,
    craftskill.rank AS rank1,
    skdworkplanextcap.resourcename,
    skdworkplanextcap.rowstamp,
    craftskill.rowstamp AS rowstamp1,
    skdworkplanextcap.skdprojectid,
    skdworkplanextcap.skdworkplanextcapid,
    skdworkplanextcap.skilllevel,
