    skdworkplanextcap.value
   FROM axioma.craftskill,
    axioma.skdworkplanextcap
  WHERE (((skdworkplanextcap.resourcename)::text = (craftskill.craft)::text) AND ((skdworkplanextcap.orgid)::text = (craftskill.orgid)::text) AND (((skdworkplanextcap.skilllevel)::text = (craftskill.skilllevel)::text) OR ((craftskill.skilllevel IS NULL) AND (skdworkplanextcap.skilllevel IS NULL))));


