-- Name: unassignedworkview; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.unassignedworkview AS
 SELECT wo.workorderid,
    wo.wonum,
    wo.siteid,
    wo.orgid,
    wo.parent,
    wo.status,
    wo.description,
    wo.schedstart,
    wo.schedfinish,
    wo.amcrew,
    wo.assetnum,
    wo.location,
    wo.crewworkgroup,
    wo.hasld,
    wo.worktype,
    wo.wopriority,
    ws.latitudey,
    ws.longitudex,
    wo.targstartdate,
    wo.targcompdate
   FROM ((axioma.workorder wo
     LEFT JOIN ( SELECT a.wonum,
            a.siteid
           FROM axioma.assignment a
          WHERE (NOT (EXISTS ( SELECT 1
                   FROM axioma.assignment b
                  WHERE (((b.status)::text IN ( SELECT synonymdomain.value
                           FROM axioma.synonymdomain
                          WHERE (((synonymdomain.maxvalue)::text = 'WAITASGN'::text) AND ((synonymdomain.domainid)::text = 'ASSTAT'::text)))) AND ((a.wonum)::text = (b.wonum)::text) AND ((a.orgid)::text = (b.orgid)::text)))))) sa ON ((((wo.wonum)::text = (sa.wonum)::text) AND ((wo.siteid)::text = (sa.siteid)::text))))
     LEFT JOIN axioma.woserviceaddress ws ON ((((ws.wonum)::text = (wo.wonum)::text) AND ((ws.siteid)::text = (wo.siteid)::text))))
  WHERE ((wo.istask = 0) AND (sa.wonum IS NULL) AND ((wo.woclass)::text IN ( SELECT synonymdomain.value
           FROM axioma.synonymdomain
          WHERE (((synonymdomain.maxvalue)::text = 'WORKORDER'::text) AND ((synonymdomain.domainid)::text = 'WOCLASS'::text)))) AND (NOT ((wo.wonum)::text IN ( SELECT tw.parent
           FROM axioma.workorder tw
          WHERE (((tw.siteid)::text = (wo.siteid)::text) AND (tw.istask = 1) AND ((tw.parent)::text = (wo.wonum)::text) AND (tw.parent IS NOT NULL))
          GROUP BY tw.parent
        EXCEPT
         SELECT tw.parent
           FROM axioma.workorder tw
          WHERE ((tw.istask = 1) AND ((tw.parent)::text = (wo.wonum)::text) AND ((tw.siteid)::text = (wo.siteid)::text) AND (NOT ((tw.wonum)::text IN ( SELECT ta.wonum
                   FROM axioma.assignment ta,
                    axioma.workorder wwa
                  WHERE (((ta.siteid)::text = (wo.siteid)::text) AND ((wwa.siteid)::text = (wo.siteid)::text) AND ((wwa.parent)::text = (tw.parent)::text) AND (NOT ((ta.status)::text IN ( SELECT synonymdomain.value
                           FROM axioma.synonymdomain
                          WHERE (((synonymdomain.maxvalue)::text = 'WAITASGN'::text) AND ((synonymdomain.domainid)::text = 'ASSTAT'::text))))))))))))));


