--
-- TOC entry 2490 (class 1259 OID 22331)
-- Name: wpmaterial; Type: VIEW; Schema: axioma; Owner: axioma
--

CREATE VIEW axioma.wpmaterial AS
 SELECT wpitem.amcrew,
    wpitem.amcrewtype,
    wpitem.catalogcode,
    wpitem.conditioncode,
    wpitem.description,
    wpitem.directreq,
    wpitem.hasld,
    wpitem.hours,
    wpitem.issueto,
    wpitem.itemnum,
    wpitem.itemqty,
    wpitem.itemsetid,
    wpitem.langcode,
    wpitem.linecost,
    wpitem.linetype,
    wpitem.location,
    wpitem.manufacturer,
    wpitem.mktplcitem,
    wpitem.modelnum,
    wpitem.orderunit,
    wpitem.orgid,
    wpitem.pr,
    wpitem.prlinenum,
    wpitem.rate,
    wpitem.ratehaschanged,
    wpitem.requestby,
    wpitem.requestnum,
    wpitem.requiredate,
    wpitem.restype,
    wpitem.rowstamp,
    wpitem.siteid,
    wpitem.storelocsite,
    wpitem.unitcost,
    wpitem.unitcosthaschanged,
    wpitem.vendor,
    wpitem.vendorpackcode,
    wpitem.vendorpackquantity,
    wpitem.vendorunitcost,
    wpitem.vendorwarehouse,
    wpitem.wonum,
    wpitem.wpitemid,
    wpitem.wplaborref,
    wpitem.wpm1,
    wpitem.wpm2,
    wpitem.wpm3,
    wpitem.wpm4,
    wpitem.wpm5,
    wpitem.wpm6
   FROM axioma.wpitem
  WHERE ((wpitem.linetype)::text IN ( SELECT synonymdomain.value
           FROM axioma.synonymdomain
          WHERE (((synonymdomain.domainid)::text = 'LINETYPE'::text) AND ((synonymdomain.maxvalue)::text = ANY (ARRAY[('ITEM'::character varying)::text, ('MATERIAL'::character varying)::text, ('EXTERNAL'::character varying)::text, ('SPORDER'::character varying)::text])))));


ALTER VIEW axioma.wpmaterial OWNER TO axioma;

